-- Migration: tandai SLS prioritas (dari SLS Prioritas Termin 1 (2).xlsx,
-- gabungan 8 sheet kecamatan: Huu, Dompu, Woja, Pajo, kilo, Kempo, Pekat, manggelewa)
-- untuk pembayaran bulan pertama SE2026 — dilihat dari status keberadaan usaha.
-- Aman dijalankan berulang (kompatibel MySQL & MariaDB lama yang belum dukung
-- ADD COLUMN IF NOT EXISTS).

DROP PROCEDURE IF EXISTS _add_sls_prioritas_column;

DELIMITER //
CREATE PROCEDURE _add_sls_prioritas_column()
BEGIN
    IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'sls' AND COLUMN_NAME = 'prioritas') THEN
        ALTER TABLE sls ADD COLUMN prioritas TINYINT(1) NOT NULL DEFAULT 0 AFTER target;
    END IF;
END //
DELIMITER ;

CALL _add_sls_prioritas_column();
DROP PROCEDURE IF EXISTS _add_sls_prioritas_column;

